# Second Brain Sync Script
# Synchronisiert OpenClaw Sessions mit Obsidian Second Brain

param(
    [string]$SourcePath = "$env:USERPROFILE\.openclaw\workspace\memory",
    [string]$TargetPath = "$PSScriptRoot\..\..\SecondBrain\01-Sessions",
    [switch]$DryRun
)

Write-Host "=== Second Brain Sync ===" -ForegroundColor Cyan
Write-Host "Source: $SourcePath" -ForegroundColor Gray
Write-Host "Target: $TargetPath" -ForegroundColor Gray
Write-Host ""

# Prüfe Pfade
if (!(Test-Path $SourcePath)) {
    Write-Error "Source path not found: $SourcePath"
    exit 1
}

if (!(Test-Path $TargetPath)) {
    Write-Host "Creating target directory..." -ForegroundColor Yellow
    if (!$DryRun) {
        New-Item -ItemType Directory -Path $TargetPath -Force | Out-Null
    }
}

# Synchronisiere Session-Dateien
$sessionFiles = Get-ChildItem -Path $SourcePath -Filter "*.md" | Where-Object { $_.Name -match '^\d{4}-\d{2}-\d{2}\.md$' }

$synced = 0
$skipped = 0

foreach ($file in $sessionFiles) {
    $targetFile = Join-Path $TargetPath $file.Name

    if (Test-Path $targetFile) {
        # Prüfe ob Update nötig
        $sourceHash = (Get-FileHash $file.FullName -Algorithm MD5).Hash
        $targetHash = (Get-FileHash $targetFile -Algorithm MD5).Hash

        if ($sourceHash -eq $targetHash) {
            Write-Host "[SKIP] $($file.Name) - identical" -ForegroundColor Gray
            $skipped++
            continue
        }
    }

    Write-Host "[SYNC] $($file.Name)" -ForegroundColor Green

    if (!$DryRun) {
        Copy-Item $file.FullName $targetFile -Force
    }

    $synced++
}

Write-Host ""
Write-Host "=== Sync Complete ===" -ForegroundColor Cyan
Write-Host "Synced: $synced" -ForegroundColor Green
Write-Host "Skipped: $skipped" -ForegroundColor Gray

if ($DryRun) {
    Write-Host "[DRY RUN - No files were copied]" -ForegroundColor Yellow
}

